def _add_social_account_list_arguments(parser: argparse.ArgumentParser) -> None:
    _add_common_adapter_arguments(parser)
    parser.add_argument("--platform", help="Omit to list accounts across all platforms.")
    parser.add_argument(
        "--search",
        help="Single search term only. For multiple known handles, repeat --search-term.",
    )
    parser.add_argument(
        "--search-term",
        action="append",
        dest="search_terms",
        help=(
            "Exact batch handle term; repeat to match many handles in one request. "
            "Leading @ or TikTok profile URLs are accepted. Max 100 terms."
        ),
    )
    parser.add_argument(
        "--plan-status",
        choices=SOCIAL_ACCOUNT_PLAN_STATUS_CHOICES,
        default="all",
    )
    parser.add_argument(
        "--allocation-type",
        choices=kebab_choices(SOCIAL_ACCOUNT_ALLOCATION_TYPE_CHOICES),
        default="all",
    )
    parser.add_argument("--allocation-status")
    parser.add_argument("--oauth-status", choices=["active", "expired", "unverified"])
    parser.add_argument("--issue-type")
    parser.add_argument("--performance-level", action="append", dest="performance_levels")
    parser.add_argument("--include-null-level", action="store_true")
    parser.add_argument(
        "--tag",
        help="Filter by workspace tag (single value, set via +assets-set --tag).",
    )
    parser.add_argument("--group-name")
    parser.add_argument("--lookup-status")
    parser.add_argument("--include-inactive", action="store_true")
    public_group = parser.add_mutually_exclusive_group()
    public_group.add_argument("--public-only", action="store_true")
    public_group.add_argument("--private-only", action="store_true")
    device_group = parser.add_mutually_exclusive_group()
    device_group.add_argument("--has-device", action="store_true")
    device_group.add_argument("--without-device", action="store_true")
    parser.add_argument("--page", type=int, default=1)
    parser.add_argument("--page-size", type=int, default=100)


def _build_social_account_list_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload = _load_structured_args(args)
    search_terms = _ordered_strings(args.search_terms) if args.search_terms else None
    if search_terms and len(search_terms) > SOCIAL_ACCOUNT_SEARCH_TERMS_MAX:
        raise ValueError(
            f"social-account +list supports at most {SOCIAL_ACCOUNT_SEARCH_TERMS_MAX} "
            "--search-term values per request."
        )
    payload.update(
        _without_none(
            {
                "platform": args.platform,
                "search": args.search,
                "search_terms": search_terms,
                "automation_status": (args.plan_status if args.plan_status != "all" else None),
                "allocation_type": (
                    dekebab(args.allocation_type) if args.allocation_type != "all" else None
                ),
                "allocation_status": args.allocation_status,
                "oauth_status": args.oauth_status,
                "issue_type": args.issue_type,
                "performance_levels": (
                    ",".join(args.performance_levels) if args.performance_levels else None
                ),
                "include_null_level": True if args.include_null_level else None,
                "tag": args.tag,
                "group_name": args.group_name,
                "lookup_status": args.lookup_status,
                "is_active": None if args.include_inactive else True,
                "is_public": (True if args.public_only else False if args.private_only else None),
                "has_device": (True if args.has_device else False if args.without_device else None),
                "page": args.page,
                "page_size": args.page_size,
            }
        )
    )
    return payload


