def _build_social_account_assets_set_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload = _build_social_account_id_arguments(args)
    changes: dict[str, Any] = {}
    if args.persona_id is not None:
        changes["persona_id"] = args.persona_id
    if args.product_id is not None:
        changes["product_id"] = args.product_id
    elif args.clear_product:
        changes["product_id"] = None
    if args.format_ids is not None:
        changes["format_ids"] = _ordered_strings(args.format_ids)
    elif args.clear_formats:
        changes["format_ids"] = []
    if args.content_topic_ids is not None:
        changes["content_topic_ids"] = _ordered_strings(args.content_topic_ids)
    elif args.clear_content_topics:
        changes["content_topic_ids"] = []
    if getattr(args, "bgm_asset_ids", None) is not None:
        changes["bgm_asset_ids"] = _ordered_strings(args.bgm_asset_ids)
    elif getattr(args, "clear_bgm_assets", False):
        changes["bgm_asset_ids"] = []
    # Workspace tags ride the same command surface but are a separate backend
    # resource (PUT .../workspace-tags), so they are NOT part of "changes".
    tags: list[str] | None = None
    if getattr(args, "tags", None) is not None:
        tags = _ordered_strings(args.tags)
    elif getattr(args, "clear_tags", False):
        tags = []
    if not changes and tags is None:
        raise ValueError("social-account +assets-set requires at least one asset change.")
    if changes:
        if args.managed_operation_approved:
            changes["managed_operation_approved"] = True
        if args.approval_note:
            changes["approval_note"] = args.approval_note.strip()
        payload["changes"] = changes
    if tags is not None:
        payload["tags"] = tags
    return payload


