def _build_social_account_version_create_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload = _build_social_account_id_arguments(args)
    if args.rules_json and args.rules_file:
        raise ValueError(
            "social-account +version-create accepts either --rules-json or --rules-file."
        )
    if args.rules_file:
        schedule_rules = _json_list(
            Path(args.rules_file).read_text(encoding="utf-8"),
            flag="--rules-file",
        )
    elif args.rules_json:
        schedule_rules = _json_list(args.rules_json, flag="--rules-json")
    else:
        schedule_rules = []
    payload["schedule_rules"] = schedule_rules
    if args.change_note is not None:
        payload["change_note"] = args.change_note
    return payload


