def _build_social_account_profile_edit_batch_submit_arguments(
    args: argparse.Namespace,
) -> dict[str, Any]:
    payload = _load_structured_args(args)
    try:
        account_updates = json.loads(args.account_updates)
    except json.JSONDecodeError as exc:
        raise ValueError(
            f"--account-updates must be valid JSON: {exc}"
        ) from exc
    if not isinstance(account_updates, list) or not account_updates:
        raise ValueError(
            "--account-updates must be a non-empty JSON array"
        )
    payload["account_updates"] = account_updates
    payload["update_nick_name"] = getattr(args, "update_nick_name", False)
    payload["update_bio"] = getattr(args, "update_bio", False)
    payload["update_avatar"] = getattr(args, "update_avatar", False)
    if args.avatar_url:
        payload["avatar_url"] = args.avatar_url
    payload["wait"] = args.wait
    payload["wait_timeout_seconds"] = args.timeout
    payload["poll_interval_seconds"] = args.poll_interval
    return payload


def _social_account_schedule_payload_from_args(
    args: argparse.Namespace,
    *,
    require_fields: bool,
) -> dict[str, Any]:
    payload = _without_none(
        {
            "scheduled_at": getattr(args, "scheduled_at", None),
            "timezone": getattr(args, "timezone", None),
            "format_id": getattr(args, "format_id", None),
            "content_topic_id": getattr(args, "content_topic_id", None),
            "generation_id": getattr(args, "generation_id", None),
            "caption": getattr(args, "caption", None),
            "hashtags": list(args.hashtags) if getattr(args, "hashtags", None) else None,
            "status": getattr(args, "status", None),
            "override_reason": getattr(args, "override_reason", None),
        }
    )
    metadata_json = getattr(args, "metadata_json", None)
    if metadata_json:
        payload["metadata"] = _json_object(metadata_json, flag="--metadata-json")
    if getattr(args, "required_mentions_json", None):
        payload["required_mentions"] = _json_list(
            args.required_mentions_json,
            flag="--required-mentions-json",
        )
    elif getattr(args, "required_mentions", None):
        payload["required_mentions"] = list(args.required_mentions)
    if getattr(args, "required_hashtags_json", None):
        payload["required_hashtags"] = _json_list(
            args.required_hashtags_json,
            flag="--required-hashtags-json",
        )
    elif getattr(args, "required_hashtags", None):
        payload["required_hashtags"] = list(args.required_hashtags)
    bgm_by_platform = _social_account_schedule_bgm_from_args(args)
    if bgm_by_platform is not None:
        payload["bgm_by_platform"] = bgm_by_platform
    if require_fields:
        require_fields_tuple = ("scheduled_at", "format_id", "content_topic_id")
        missing = [field for field in require_fields_tuple if not payload.get(field)]
        if missing:
            raise ValueError(
                "social-account +schedule-create missing required fields: " + ", ".join(missing)
            )
    return payload


def _social_account_schedule_bgm_from_args(
    args: argparse.Namespace,
) -> dict[str, Any] | None:
    if getattr(args, "bgm_by_platform_json", None):
        return _json_object(args.bgm_by_platform_json, flag="--bgm-by-platform-json")
    if getattr(args, "clear_music", False):
        return {}
    music_fields = {
        "music_name": getattr(args, "music_name", None),
        "url": getattr(args, "music_url", None),
        "source_url": getattr(args, "music_url", None),
        "ref_video_id": getattr(args, "music_ref_video_id", None),
    }
    music_config = {
        key: value.strip()
        for key, value in music_fields.items()
        if isinstance(value, str) and value.strip()
    }
    if not music_config:
        return None
    platform = str(getattr(args, "music_platform", None) or "tiktok").strip().lower()
    if not platform:
        platform = "tiktok"
    return {platform: music_config}


