def _add_social_account_connect_link_create_arguments(parser: argparse.ArgumentParser) -> None:
    _add_common_adapter_arguments(parser)
    parser.add_argument("--platform", choices=SOCIAL_ACCOUNT_CONNECT_PLATFORM_CHOICES)
    parser.add_argument("--expires-in-days", type=int, default=7)
    parser.add_argument("--redirect-url")
    parser.add_argument("--dry-run", action="store_true")


def _build_social_account_connect_link_create_arguments(
    args: argparse.Namespace,
) -> dict[str, Any]:
    payload = _load_structured_args(args)
    if args.platform is not None:
        payload["platform"] = args.platform
    payload["expires_in_days"] = args.expires_in_days
    # A connect link authorizes exactly one platform; a silent default here
    # used to mint TikTok links when the flag was forgotten, so the platform
    # must always be stated explicitly (flag or structured args).
    platform = payload.get("platform")
    if platform not in SOCIAL_ACCOUNT_CONNECT_PLATFORM_CHOICES:
        choices = "|".join(SOCIAL_ACCOUNT_CONNECT_PLATFORM_CHOICES)
        raise ValueError(f"social-account +connect-link-create requires --platform ({choices}).")
    if args.redirect_url is not None:
        payload["redirect_url"] = args.redirect_url
    return payload


def _add_social_account_connect_link_status_arguments(parser: argparse.ArgumentParser) -> None:
    _add_common_adapter_arguments(parser)
    parser.add_argument("--id", dest="link_id", required=True)
    parser.add_argument("--wait", action="store_true")
    parser.add_argument("--timeout", type=int, default=0)
    parser.add_argument("--poll-interval", type=float, default=2.0)


def _build_social_account_connect_link_status_arguments(
    args: argparse.Namespace,
) -> dict[str, Any]:
    payload = _load_structured_args(args)
    payload.update(
        {
            "link_id": args.link_id,
            "wait": args.wait,
            "timeout": args.timeout,
            "poll_interval": args.poll_interval,
        }
    )
    if not str(payload.get("link_id") or "").strip():
        raise ValueError("social-account +connect-link-status requires --id.")
    return payload


def _social_account_connect_link_create_input_schema() -> dict[str, Any]:
    return {
        "type": "object",
        "properties": {
            "platform": {
                "type": "string",
                "enum": SOCIAL_ACCOUNT_CONNECT_PLATFORM_CHOICES,
                "description": (
                    "User-owned account platform to authorize. Required — always "
                    "pass the platform the user asked to connect."
                ),
            },
            "expires_in_days": {
                "type": ["integer", "null"],
                "minimum": 1,
                "default": 7,
                "description": (
                    "TikTok connect link lifetime. Ignored for managed OAuth platforms."
                ),
            },
            "redirect_url": {
                "type": ["string", "null"],
                "format": "uri",
                "description": "Optional OAuth redirect URL for managed OAuth platforms.",
            },
        },
        "required": ["platform"],
    }


def _social_account_connect_link_status_input_schema() -> dict[str, Any]:
    return {
        "type": "object",
        "properties": {
            "link_id": _uuid_id_schema("Connect link UUID returned by +connect-link-create."),
            "wait": {
                "type": "boolean",
                "default": False,
                "description": "Poll until completed, expired, revoked, or timeout.",
            },
            "timeout": {
                "type": "integer",
                "minimum": 0,
                "maximum": 3600,
                "default": 0,
            },
            "poll_interval": {
                "type": "number",
                "minimum": 0.1,
                "maximum": 60,
                "default": 2.0,
            },
        },
        "required": ["link_id"],
    }


def _add_social_account_performance_get_arguments(parser: argparse.ArgumentParser) -> None:
    _add_social_account_id_arguments(parser)
    parser.add_argument(
        "--period",
        choices=SOCIAL_ACCOUNT_PERFORMANCE_PERIOD_CHOICES,
        default="last-30d",
    )
    parser.add_argument(
        "--cursor",
        help="Opaque pagination cursor; pass page.next_cursor from the previous call.",
    )
    parser.add_argument("--page-size", type=int, default=20)


def _build_social_account_performance_get_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload = _build_social_account_id_arguments(args)
    payload.update(
        _without_none(
            {
                "period": dekebab(args.period),
                "cursor": args.cursor,
                "page_size": args.page_size,
            }
        )
    )
    return payload


def _social_account_performance_get_input_schema() -> dict[str, Any]:
    return {
        "type": "object",
        "properties": {
            "account_id": _uuid_id_schema("Pool account UUID."),
            "period": {
                "type": "string",
                "enum": ["last_7d", "last_30d", "last_60d"],
                "default": "last_30d",
            },
            "cursor": {
                "type": ["string", "null"],
                "description": (
                    "Opaque pagination cursor. Omit for the first page (which also "
                    "includes the account-level profile block); pass page.next_cursor "
                    "from the previous response for the next page of posts."
                ),
            },
            "page_size": {
                "type": "integer",
                "minimum": 1,
                "maximum": 50,
                "default": 20,
            },
        },
        "required": ["account_id"],
    }


