async def _execute_assets_set(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    command_name = ctx.spec.schema_name
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    account_id = str(arguments.get("account_id") or "")
    if not account_id:
        raise RuntimeError(f"{command_name} requires account_id")
    changes = _dict_argument(arguments, "changes") if arguments.get("changes") else {}
    tags = arguments.get("tags")
    if not changes and tags is None:
        raise RuntimeError(f"{command_name} requires at least one asset change")

    # Single-part calls keep the legacy response shape. Mixed calls run the
    # two backend resources independently (publish assets are gated by
    # allocation, workspace tags are not) and report each part's outcome —
    # a 409 on assets must not hide that the tags were applied.
    if changes and tags is None:
        return await _social_account_set_publish_assets(
            cfg,
            workspace_id=workspace_id,
            account_id=account_id,
            changes=changes,
        )
    if tags is not None and not changes:
        return await _social_account_set_workspace_tags(
            cfg,
            workspace_id=workspace_id,
            account_id=account_id,
            tags=list(tags),
        )

    sections: dict[str, Any] = {}
    errors: list[str] = []
    try:
        sections["workspace_tags"] = {
            "ok": True,
            "data": await _social_account_set_workspace_tags(
                cfg,
                workspace_id=workspace_id,
                account_id=account_id,
                tags=list(tags or []),
            ),
        }
    except RuntimeError as exc:
        sections["workspace_tags"] = {"ok": False, "error": str(exc)}
        errors.append(f"workspace_tags: {exc}")
    try:
        sections["publish_assets"] = {
            "ok": True,
            "data": await _social_account_set_publish_assets(
                cfg,
                workspace_id=workspace_id,
                account_id=account_id,
                changes=changes,
            ),
        }
    except RuntimeError as exc:
        sections["publish_assets"] = {"ok": False, "error": str(exc)}
        errors.append(f"publish_assets: {exc}")
    if len(errors) == len(sections):
        raise RuntimeError("; ".join(errors))
    return sections


