async def _poll_connect_link_status(
    cfg: Config,
    *,
    workspace_id: str,
    link_id: str,
    wait: bool,
    timeout_seconds: int,
    poll_interval_seconds: float,
) -> Any:
    terminal_statuses = {"completed", "expired", "revoked"}
    started_at = asyncio.get_running_loop().time()
    while True:
        result = agent_domain_result(
            await api_data(
                cfg,
                "GET",
                f"/agent-cli/social-auth/connect-links/{link_id}/status",
                params={"workspace_id": workspace_id},
            )
        )
        if not wait or not isinstance(result, dict) or result.get("status") in terminal_statuses:
            return result
        if timeout_seconds <= 0:
            return result
        elapsed = asyncio.get_running_loop().time() - started_at
        if elapsed >= timeout_seconds:
            return {**result, "timed_out": True}
        await asyncio.sleep(min(max(poll_interval_seconds, 0.1), timeout_seconds - elapsed))


async def _poll_avatar_generate_status(
    cfg: Config,
    *,
    task_id: str,
    timeout_seconds: float,
    poll_interval_seconds: float,
) -> Any:
    deadline = time.monotonic() + max(timeout_seconds, 0.0)
    interval = max(poll_interval_seconds, 0.25)
    last_result: Any = None
    while True:
        last_result = agent_domain_result(
            await api_data(
                cfg,
                "GET",
                f"/agent-cli/social-accounts/profile-edit/avatar-drafts/{task_id}",
            )
        )
        if _profile_edit_status_is_settled(last_result):
            return last_result
        if time.monotonic() >= deadline:
            return {
                "timed_out": True,
                "task_id": task_id,
                "last_status": last_result,
            }
        await asyncio.sleep(interval)


async def _poll_profile_edit_status(
    cfg: Config,
    *,
    task_id: str,
    timeout_seconds: float,
    poll_interval_seconds: float,
) -> Any:
    deadline = time.monotonic() + max(timeout_seconds, 0.0)
    interval = max(poll_interval_seconds, 0.25)
    last_result: Any = None
    while True:
        last_result = agent_domain_result(
            await api_data(
                cfg,
                "GET",
                f"/agent-cli/social-accounts/profile-edit/tasks/{task_id}",
            )
        )
        if _profile_edit_status_is_settled(last_result):
            return last_result
        if time.monotonic() >= deadline:
            return {
                "timed_out": True,
                "task_id": task_id,
                "last_status": last_result,
            }
        await asyncio.sleep(interval)


def _profile_edit_status_is_settled(result: Any) -> bool:
    if not isinstance(result, dict):
        return False
    summary = result.get("summary")
    return isinstance(summary, dict) and summary.get("settled") is True


